const source = items[0]?.json ?? {};

function parseJsonField(name, fallback) {
  const value = source[name];
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value !== 'string') return value;
  try {
    return JSON.parse(value);
  } catch (error) {
    throw new Error(`${name} must be valid JSON: ${error.message}`);
  }
}

const riskThreshold = Number(source.risk_threshold ?? 65);
const topN = Number(source.top_n ?? 10);
const lookbackDays = Number(source.lookback_days ?? 30);

if (!Number.isFinite(riskThreshold) || riskThreshold < 0 || riskThreshold > 100) {
  throw new Error('risk_threshold must be a number between 0 and 100');
}
if (!Number.isInteger(topN) || topN < 1 || topN > 100) {
  throw new Error('top_n must be an integer between 1 and 100');
}
if (!Number.isInteger(lookbackDays) || lookbackDays < 1 || lookbackDays > 365) {
  throw new Error('lookback_days must be an integer between 1 and 365');
}

const usageSignals = parseJsonField('usage_signals', []);
const billingSignals = parseJsonField('billing_signals', []);
const crmSignals = parseJsonField('crm_signals', []);
const supportSignals = parseJsonField('support_signals', []);
const simulateSourceFailures = parseJsonField('simulate_source_failures', {});

for (const [name, value] of Object.entries({ usageSignals, billingSignals, crmSignals, supportSignals })) {
  if (!Array.isArray(value)) {
    throw new Error(`${name} must be an array`);
  }
}

const runDate = new Date().toISOString().slice(0, 10);
const scoringVersion = 'churn-risk-rules-v2';

return [{
  json: {
    risk_threshold: riskThreshold,
    top_n: topN,
    lookback_days: lookbackDays,
    source_payloads: {
      usage: usageSignals,
      billing: billingSignals,
      crm: crmSignals,
      support: supportSignals,
    },
    simulate_source_failures: simulateSourceFailures,
    control: {
      run_date: runDate,
      scoring_version: scoringVersion,
      retry_policy: {
        max_attempts: 3,
        timeout_ms: 30000,
        backoff: 'exponential',
        retry_on: ['429', '408', '5xx', 'network_timeout'],
      },
      source_names: ['usage', 'billing', 'crm', 'support'],
      data_minimisation: 'Send account-level summaries only. Avoid raw transcripts and unnecessary personal data in optional LLM steps.',
    },
  },
}];

const root = { ...items[0].json };
const sourceName = 'usage';
const checkedAt = new Date().toISOString();

function daysBetween(dateA, dateB) {
  const a = new Date(`${dateA}T00:00:00Z`);
  const b = new Date(`${dateB}T00:00:00Z`);
  return Math.round((b - a) / 86400000);
}

try {
  if (root.simulate_source_failures?.[sourceName]) {
    throw new Error(`Simulated ${sourceName} source failure`);
  }

  const rawRecords = root.source_payloads?.[sourceName] ?? [];
  const warnings = [];
  const records = [];

  for (const record of rawRecords) {
    if (!record || typeof record !== 'object' || !record.account_id) {
      warnings.push(`Dropped ${sourceName} record without account_id`);
      continue;
    }
    records.push(record);
  }

  let status = 'success';
  if (records.length === 0) status = 'empty';
  else if (warnings.length > 0) status = 'partial';

  const result = {
    source: sourceName,
    status,
    checked_at: checkedAt,
    source_timestamp: checkedAt,
    record_count: records.length,
    records,
    warnings,
    retry_policy: root.control?.retry_policy,
  };

  return [{
    json: {
      ...root,
      [`${sourceName}_source_result`]: result,
    },
  }];
} catch (error) {
  const result = {
    source: sourceName,
    status: 'failed',
    checked_at: checkedAt,
    source_timestamp: null,
    record_count: 0,
    records: [],
    warnings: [`${sourceName} source unavailable`],
    error: error.message,
    retry_policy: root.control?.retry_policy,
  };

  return [{
    json: {
      ...root,
      [`${sourceName}_source_result`]: result,
    },
  }];
}

