const root = items[0]?.json ?? {};
const sourceResults = Object.fromEntries((root.control?.source_names ?? ['usage', 'billing', 'crm', 'support']).map(name => [name, root[`${name}_source_result`]]));
const runDate = root.control?.run_date ?? new Date().toISOString().slice(0, 10);
const sourceWarnings = [];
const sourceStatuses = {};

for (const sourceName of root.control?.source_names ?? ['usage', 'billing', 'crm', 'support']) {
  const result = sourceResults[sourceName] ?? { status: 'failed', warnings: [`${sourceName} source missing from workflow output`] };
  sourceStatuses[sourceName] = {
    status: result.status,
    checked_at: result.checked_at,
    source_timestamp: result.source_timestamp,
    record_count: result.record_count ?? 0,
    error: result.error,
    warnings: result.warnings ?? [],
  };

  if (['failed', 'empty', 'partial'].includes(result.status)) {
    sourceWarnings.push(`${sourceName}: ${result.status}${result.error ? ` (${result.error})` : ''}`);
  }
}

function daysUntil(dateString) {
  if (!dateString) return null;
  const date = new Date(`${dateString}T00:00:00Z`);
  if (Number.isNaN(date.getTime())) return null;
  const now = new Date(`${runDate}T00:00:00Z`);
  return Math.ceil((date - now) / 86400000);
}

function byAccount(records = []) {
  const map = new Map();
  for (const record of records) {
    if (record?.account_id) map.set(record.account_id, record);
  }
  return map;
}

const usageByAccount = byAccount(sourceResults.usage?.records);
const billingByAccount = byAccount(sourceResults.billing?.records);
const crmByAccount = byAccount(sourceResults.crm?.records);
const supportByAccount = byAccount(sourceResults.support?.records);

const accountIds = new Set([
  ...usageByAccount.keys(),
  ...billingByAccount.keys(),
  ...crmByAccount.keys(),
  ...supportByAccount.keys(),
]);

const accounts = [...accountIds].sort().map(accountId => {
  const usage = usageByAccount.get(accountId) ?? null;
  const billing = billingByAccount.get(accountId) ?? null;
  const crm = crmByAccount.get(accountId) ?? null;
  const support = supportByAccount.get(accountId) ?? null;

  const missingSources = [];
  if (!usage) missingSources.push('usage');
  if (!billing) missingSources.push('billing');
  if (!crm) missingSources.push('crm');
  if (!support) missingSources.push('support');

  const seatsUsed = Number(usage?.seats_used ?? 0);
  const seatsPurchased = Number(usage?.seats_purchased ?? 0);
  const seatUtilisationPct = seatsPurchased > 0 ? Math.round((seatsUsed / seatsPurchased) * 100) : null;

  return {
    account_id: accountId,
    account_name: crm?.account_name ?? accountId,
    owner: crm?.owner ?? 'Unassigned',
    plan: billing?.plan ?? 'unknown',
    mrr: Number(billing?.mrr ?? 0),
    renewal_date: billing?.renewal_date ?? null,
    days_to_renewal: daysUntil(billing?.renewal_date),
    payment_status: billing?.payment_status ?? 'unknown',
    downgrade_requested: Boolean(billing?.downgrade_requested),
    last_active_date: usage?.last_active_date ?? null,
    logins_30d: Number(usage?.logins_30d ?? 0),
    feature_events_30d: Number(usage?.feature_events_30d ?? 0),
    usage_trend_pct: Number(usage?.usage_trend_pct ?? 0),
    seats_used: seatsUsed,
    seats_purchased: seatsPurchased,
    seat_utilisation_pct: seatUtilisationPct,
    health_status: crm?.health_status ?? 'unknown',
    last_qbr_date: crm?.last_qbr_date ?? null,
    executive_sponsor_engaged: Boolean(crm?.executive_sponsor_engaged),
    high_priority_tickets_30d: Number(support?.high_priority_tickets_30d ?? 0),
    open_tickets: Number(support?.open_tickets ?? 0),
    csat_avg: support?.csat_avg ?? null,
    nps_score: support?.nps_score ?? null,
    support_themes: support?.themes ?? [],
    missing_sources: missingSources,
  };
});

if (accounts.length === 0) {
  throw new Error('No account records available after source collection');
}

return [{
  json: {
    ...root,
    accounts,
    source_statuses: sourceStatuses,
    source_warnings: sourceWarnings,
    aggregation_status: sourceWarnings.length ? 'partial' : 'success',
  },
}];

const root = items[0]?.json ?? {};
const alerts = [];

for (const [sourceName, status] of Object.entries(root.source_statuses ?? {})) {
  if (['failed', 'partial', 'empty'].includes(status.status)) {
    alerts.push({
      alert_type: 'churn_source_collection_issue',
      source: sourceName,
      status: status.status,
      checked_at: status.checked_at,
      error: status.error ?? null,
      warnings: status.warnings ?? [],
      recommended_action: `Review ${sourceName} source connector, credentials, rate limits and freshness before relying on today's churn-risk watchlist.`,
    });
  }
}

return [{
  json: {
    ...root,
    operations_alerts: alerts,
    operations_alert_status: alerts.length ? 'prepared' : 'not_required',
  },
}];

const root = items[0]?.json ?? {};
const runDate = root.control?.run_date ?? new Date().toISOString().slice(0, 10);

function daysSince(dateString) {
  if (!dateString) return null;
  const date = new Date(`${dateString}T00:00:00Z`);
  if (Number.isNaN(date.getTime())) return null;
  const now = new Date(`${runDate}T00:00:00Z`);
  return Math.floor((now - date) / 86400000);
}

function severity(score) {
  if (score >= 85) return 'critical';
  if (score >= 70) return 'high';
  if (score >= 45) return 'medium';
  return 'low';
}

const scored_accounts = (root.accounts ?? []).map(account => {
  let score = 0;
  const reasons = [];

  const inactiveDays = daysSince(account.last_active_date);
  if (inactiveDays !== null && inactiveDays >= 30) { score += 25; reasons.push(`No product activity for ${inactiveDays} days`); }
  else if (inactiveDays !== null && inactiveDays >= 14) { score += 15; reasons.push(`Reduced activity: ${inactiveDays} days since last active`); }

  if (account.usage_trend_pct <= -60) { score += 20; reasons.push(`Usage down ${Math.abs(account.usage_trend_pct)}%`); }
  else if (account.usage_trend_pct <= -30) { score += 12; reasons.push(`Usage down ${Math.abs(account.usage_trend_pct)}%`); }

  if (account.seat_utilisation_pct !== null && account.seat_utilisation_pct < 30) { score += 15; reasons.push(`Low seat utilisation at ${account.seat_utilisation_pct}%`); }
  else if (account.seat_utilisation_pct !== null && account.seat_utilisation_pct < 50) { score += 8; reasons.push(`Seat utilisation below target at ${account.seat_utilisation_pct}%`); }

  if (account.days_to_renewal !== null && account.days_to_renewal <= 30) { score += 18; reasons.push(`Renewal in ${account.days_to_renewal} days`); }
  else if (account.days_to_renewal !== null && account.days_to_renewal <= 60) { score += 10; reasons.push(`Renewal in ${account.days_to_renewal} days`); }

  if (account.payment_status === 'failed') { score += 18; reasons.push('Recent failed payment'); }
  if (account.downgrade_requested) { score += 20; reasons.push('Downgrade requested'); }

  if (account.health_status === 'red') { score += 18; reasons.push('CRM health status is red'); }
  else if (account.health_status === 'yellow') { score += 8; reasons.push('CRM health status is yellow'); }

  if (!account.executive_sponsor_engaged && account.mrr >= 4000) { score += 8; reasons.push('No executive sponsor engagement on material account'); }

  if (account.high_priority_tickets_30d >= 4) { score += 18; reasons.push(`${account.high_priority_tickets_30d} high-priority support tickets in 30 days`); }
  else if (account.high_priority_tickets_30d >= 1) { score += 8; reasons.push(`${account.high_priority_tickets_30d} high-priority support ticket(s) in 30 days`); }

  if (typeof account.csat_avg === 'number' && account.csat_avg < 3) { score += 12; reasons.push(`Low CSAT average: ${account.csat_avg}`); }
  if (typeof account.nps_score === 'number' && account.nps_score <= 4) { score += 12; reasons.push(`Low NPS score: ${account.nps_score}`); }

  if ((account.missing_sources ?? []).length) {
    score += Math.min(10, account.missing_sources.length * 3);
    reasons.push(`Scored with missing sources: ${account.missing_sources.join(', ')}`);
  }

  score = Math.min(100, score);
  const risk_severity = severity(score);
  const topReasons = reasons.slice(0, 5);
  const outreachAngle = topReasons.length
    ? `Prioritise a ${risk_severity} risk check-in focused on ${topReasons[0].toLowerCase()}.`
    : 'Keep in standard success cadence; no urgent churn signal detected.';

  return {
    ...account,
    risk_score: score,
    risk_severity,
    risk_reasons: topReasons,
    outreach_angle: outreachAngle,
    idempotency_key: `${account.account_id}:${account.renewal_date ?? 'no-renewal'}:${root.control?.scoring_version ?? 'rules'}`,
    score_source: 'deterministic_rules',
  };
});

return [{
  json: {
    ...root,
    scored_accounts,
  },
}];

const root = items[0]?.json ?? {};
const llmDataPolicy = {
  mode: 'optional_private_or_approved_model',
  allowed_fields: ['account_name', 'owner', 'plan', 'risk_score', 'risk_severity', 'risk_reasons', 'missing_sources', 'support_themes'],
  excluded_fields: ['raw_ticket_transcripts', 'personal_contact_details', 'full_financial_records'],
  decision_boundary: 'LLM drafts wording only. Rule-based score remains the authority.',
};

const scored_accounts = (root.scored_accounts ?? []).map(account => {
  const minimalInput = {
    account_name: account.account_name,
    owner: account.owner,
    plan: account.plan,
    risk_score: account.risk_score,
    risk_severity: account.risk_severity,
    risk_reasons: account.risk_reasons,
    missing_sources: account.missing_sources,
    support_themes: account.support_themes,
  };

  const prompt = [
    'Draft a concise customer-success outreach note using only this account-level summary.',
    'Do not infer personal details. Do not change the risk score. Keep the message practical and non-alarmist.',
    JSON.stringify(minimalInput, null, 2),
  ].join('\n\n');

  const draft = account.risk_score >= root.risk_threshold
    ? `Suggested outreach: ${account.owner} should contact ${account.account_name} with a practical recovery plan covering ${account.risk_reasons.join('; ')}.`
    : 'Suggested outreach: maintain normal success cadence.';

  return {
    ...account,
    llm_usage: {
      status: 'demo_template_prepared',
      prompt,
      data_policy: llmDataPolicy,
      drafted_summary: draft,
    },
  };
});

return [{
  json: {
    ...root,
    scored_accounts,
    optional_llm_usage: {
      status: 'included_as_demo_template',
      data_policy: llmDataPolicy,
      implementation_note: 'Replace this Code node with a local or approved private LLM call if the client wants personalised wording.',
    },
  },
}];

const root = items[0]?.json ?? {};
const threshold = Number(root.risk_threshold ?? 65);
const topN = Number(root.top_n ?? 10);

const watchlist = (root.scored_accounts ?? [])
  .filter(account => account.risk_score >= threshold)
  .sort((a, b) => {
    if (b.risk_score !== a.risk_score) return b.risk_score - a.risk_score;
    if (b.mrr !== a.mrr) return b.mrr - a.mrr;
    return String(a.account_id).localeCompare(String(b.account_id));
  })
  .slice(0, topN);

return [{
  json: {
    ...root,
    watchlist,
    watchlist_count: watchlist.length,
  },
}];

const root = items[0]?.json ?? {};
const lines = [];
lines.push('# Churn Risk Watchlist');
lines.push('');
lines.push(`Run date: ${root.control?.run_date}`);
lines.push(`Scoring version: ${root.control?.scoring_version}`);
lines.push(`Threshold: ${root.risk_threshold}`);
lines.push(`Accounts on watchlist: ${root.watchlist_count}`);
lines.push(`Aggregation status: ${root.aggregation_status}`);
lines.push('');

lines.push('## Source status');
for (const [sourceName, status] of Object.entries(root.source_statuses ?? {})) {
  const parts = [`${sourceName}: ${status.status}`, `${status.record_count ?? 0} records`];
  if (status.checked_at) parts.push(`checked ${status.checked_at}`);
  if (status.error) parts.push(`error: ${status.error}`);
  lines.push(`- ${parts.join(' | ')}`);
}

if ((root.source_warnings ?? []).length) {
  lines.push('');
  lines.push('## Missing-source warnings');
  for (const warning of root.source_warnings) lines.push(`- ${warning}`);
}

lines.push('');
lines.push('## Priority accounts');

if (!(root.watchlist ?? []).length) {
  lines.push('- No accounts met the configured risk threshold.');
} else {
  for (const account of root.watchlist) {
    lines.push(`- **${account.account_name}** (${account.account_id}) — ${account.risk_severity} risk, score ${account.risk_score}, MRR £/${account.mrr}`.replace('£/', ''));
    lines.push(`  - Owner: ${account.owner}`);
    lines.push(`  - Renewal: ${account.renewal_date ?? 'unknown'} (${account.days_to_renewal ?? 'unknown'} days)`);
    lines.push(`  - Reasons: ${(account.risk_reasons ?? []).join('; ') || 'No major reason captured'}`);
    lines.push(`  - Outreach: ${account.llm_usage?.drafted_summary ?? account.outreach_angle}`);
    if ((account.missing_sources ?? []).length) lines.push(`  - Missing signals: ${account.missing_sources.join(', ')}`);
  }
}

if ((root.operations_alerts ?? []).length) {
  lines.push('');
  lines.push('## Operations alerts');
  for (const alert of root.operations_alerts) {
    lines.push(`- ${alert.source}: ${alert.status}${alert.error ? ` — ${alert.error}` : ''}`);
  }
}

const summary_markdown = lines.join('\n');

return [{
  json: {
    ...root,
    summary_markdown,
  },
}];

const root = items[0]?.json ?? {};
const tasks = (root.watchlist ?? []).map(account => ({
  task_type: 'customer_success_outreach',
  account_id: account.account_id,
  account_name: account.account_name,
  owner: account.owner,
  priority: account.risk_severity,
  risk_score: account.risk_score,
  idempotency_key: `cs-outreach:${account.idempotency_key}`,
  title: `Churn-risk follow-up: ${account.account_name}`,
  description: account.llm_usage?.drafted_summary ?? account.outreach_angle,
  due_date_hint: account.days_to_renewal !== null && account.days_to_renewal <= 30 ? 'within_2_business_days' : 'within_1_week',
}));

return [{
  json: {
    ...root,
    outreach_tasks: tasks,
    outreach_task_status: tasks.length ? 'prepared' : 'not_required',
  },
}];

const root = items[0]?.json ?? {};
const notificationPayload = {
  channel: '#customer-success',
  subject: `Churn Risk Watchlist — ${root.control?.run_date}`,
  markdown: root.summary_markdown,
  idempotency_key: `churn-watchlist:${root.control?.run_date}:${root.control?.scoring_version}`,
